145→    // ===== 读取 WAV 文件为 float 数组 =====
146→    private float[] readWav(String filepath) throws IOException {
147→        FileInputStream fis = new FileInputStream(filepath);
148→        // 跳过 WAV 头 (44字节)
149→        byte[] header = new byte[44];
150→        fis.read(header);
151→
152→        // 读取全部 PCM 数据
153→        ByteArrayOutputStream baos = new ByteArrayOutputStream();
154→        byte[] buf = new byte[8192];
155→        int n;
156→        while ((n = fis.read(buf)) != -1) baos.write(buf, 0, n);
157→        fis.close();
158→
159→        byte[] pcm = baos.toByteArray();
160→        int numSamples = pcm.length / 2;
161→        float[] samples = new float[numSamples];
162→        ByteBuffer bb = ByteBuffer.wrap(pcm).order(ByteOrder.LITTLE_ENDIAN);
163→        for (int i = 0; i < numSamples; i++) {
164→            samples[i] = bb.getShort() / 32768.0f;
165→        }
166→        return samples;
167→    }
