169→    // ===== Sherpa-ONNX 离线识别 =====
170→    private String transcribeSherpa(String audioFile) throws Exception {
171→        AssetManager assetManager = getAssets();
172→
173→        // 配置 Paraformer 模型
174→        OfflineParaformerModelConfig paraformerConfig = new OfflineParaformerModelConfig();
175→        paraformerConfig.setModel("models/paraformer/model.int8.onnx");
176→
177→        // 配置模型总参数
178→        OfflineModelConfig modelConfig = new OfflineModelConfig();
179→        modelConfig.setParaformer(paraformerConfig);
180→        modelConfig.setTokens("models/paraformer/tokens.txt");
181→        modelConfig.setNumThreads(4);
182→        modelConfig.setDebug(false);
183→
184→        // 配置识别器
185→        OfflineRecognizerConfig config = new OfflineRecognizerConfig();
186→        config.setModelConfig(modelConfig);
187→        config.setDecodingMethod("greedy_search");
188→
189→        // 创建识别器（使用 AssetManager 读取模型）
190→        OfflineRecognizer recognizer = new OfflineRecognizer(assetManager, config);
191→
192→        // 读取音频并识别
193→        float[] samples = readWav(audioFile);
194→        OfflineStream stream = recognizer.createStream();
195→        stream.acceptWaveform(samples, 16000);
196→        recognizer.decode(stream);
197→
198→        OfflineRecognizerResult result = recognizer.getResult(stream);
199→        String text = result.getText();
200→
201→        stream.release();
202→        recognizer.release();
203→
204→        return text != null ? text.trim() : "";
205→    }
